module multi_pipe_4bit(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);
    parameter size = 4;
    reg [7:0] partial_products [0:3];
    reg [7:0] registers [0:2];
    wire [7:0] add_inputs [0:2];
    wire [7:0] add_outputs [0:2];
    // Extend input signals
    wire [7:0] a = {4'd0, mul_a};
    wire [7:0] b = {4'd0, mul_b};
    // Generate partial products
    genvar i;
    generate
        for (i = 0; i < size; i = i + 1) begin : gen_partial_products
            // Select the bit in multiplier
            wire [7:0] b_selected = (b[i]) ? (a << i) : 'd0;
            // Add to the corresponding register
            always @(posedge clk, negedge rst_n) begin
                if (!rst_n) begin
                    registers[i] <= 8'd0;
                end else begin
                    registers[i] <= registers[i] + b_selected;
                end
            end
        end
    endgenerate
    // Add registers
    always @(posedge clk, negedge rst_n) begin
        if (!rst_n) begin
            registers[2] <= 8'd0;
        end else begin
            registers[2] <= add_outputs[2];
        end
    end
    // Assign the first register to the second input of adders
    assign add_inputs[0] = registers[0];
    assign add_inputs[1] = registers[1];
    assign add_inputs[2] = registers[2];
    // Add inputs
    genvar j;
    generate
        for (j = 0; j < 3; j = j + 1) begin : adder
            always @(posedge clk, negedge rst_n) begin
                if (!rst_n) begin
                    add_outputs[j] <= 8'd0;
                end else begin
                    add_outputs[j] <= add_inputs[j] + add_inputs[j+1];
                end
            end
        end
    endgenerate
    // Assign the last register to the output
    always @(posedge clk, negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 8'd0;
        end else begin
            mul_out <= registers[2];
        end
    end
endmodule
